#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void helper(char* digits, int index, char* current, char*** ans, int* returnSize, char* combos[]) {
    if (index == strlen(digits)) {
        (*returnSize)++;
        (*ans) = realloc((*ans), (*returnSize) * sizeof(char*));
        (*ans)[(*returnSize) - 1] = malloc(strlen(current) + 1);
        strcpy((*ans)[(*returnSize) - 1], current);
        return;
    }
    char* s = combos[digits[index] - '0'];
    for (int i = 0; i < strlen(s); i++) {
        current[index] = s[i];
        helper(digits, index + 1, current, ans, returnSize, combos);
    }
}

char** letterCombinations(char* digits, int* returnSize) {
    if (strlen(digits) == 0) {
        *returnSize = 0;
        return NULL;
    }
    char* combos[] = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};
    char* current = malloc(strlen(digits) + 1);
    char** ans = NULL;
    *returnSize = 0;
    helper(digits, 0, current, &ans, returnSize, combos);
    free(current);
    return ans;
}

